import (
	"net/http"
	"strconv"
	"strings"
)

// CORSOptions configures the behavior of the CORS middleware returned by
// CORS(), and of Mux's EnableCORSWithOptions().
type CORSOptions struct {
	// AllowOrigin is the value written to the Access-Control-Allow-Origin
	// header. An empty value disables the header.
	AllowOrigin string

	// AllowMethods lists the methods advertised on
	// Access-Control-Allow-Methods for a preflight request, used as a
	// fallback when chi cannot detect the methods registered for the
	// requested route.
	AllowMethods []string

	// AllowHeaders lists the headers advertised on
	// Access-Control-Allow-Headers for a preflight request.
	AllowHeaders []string

	// ExposeHeaders lists the headers advertised on
	// Access-Control-Expose-Headers. An empty value disables the header.
	ExposeHeaders []string

	// MaxAge is the number of seconds advertised on
	// Access-Control-Max-Age for a preflight request.
	MaxAge int

	// AllowCredentials sets Access-Control-Allow-Credentials to "true"
	// when enabled.
	AllowCredentials bool
}

// DefaultCORSOptions returns a CORSOptions value with permissive, sensible
// defaults: any origin, the common HTTP methods and headers, and a 1 hour
// preflight cache.
func DefaultCORSOptions() CORSOptions {
	return CORSOptions{
		AllowOrigin: "*",
		AllowMethods: []string{
			http.MethodGet, http.MethodHead, http.MethodPost,
			http.MethodPut, http.MethodPatch, http.MethodDelete,
		},
		AllowHeaders:     []string{"Accept", "Authorization", "Content-Type"},
		ExposeHeaders:    nil,
		MaxAge:           3600,
		AllowCredentials: false,
	}
}

// CORS returns a middleware that annotates responses with the headers
// necessary for Cross-Origin Resource Sharing, as configured by options.
//
// It does not itself short-circuit preflight OPTIONS requests; pair it
// with Mux's EnableCORS/EnableCORSWithOptions (which also configures the
// method-not-allowed handler) to answer preflight requests automatically.
func CORS(options CORSOptions) func(http.Handler) http.Handler {
	allowHeaders := strings.Join(options.AllowHeaders, ", ")
	maxAge := strconv.Itoa(options.MaxAge)
	exposeHeaders := strings.Join(options.ExposeHeaders, ", ")

	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			header := w.Header()
			if options.AllowOrigin != "" {
				header.Set("Access-Control-Allow-Origin", options.AllowOrigin)
			}
			if options.AllowCredentials {
				header.Set("Access-Control-Allow-Credentials", "true")
			}
			if exposeHeaders != "" {
				header.Set("Access-Control-Expose-Headers", exposeHeaders)
			}

			if r.Method == http.MethodOptions {
				header.Set("Access-Control-Allow-Headers", allowHeaders)
				header.Set("Access-Control-Max-Age", maxAge)
			}

			next.ServeHTTP(w, r)
		})
	}
}

// corsMethodNotAllowedHandler builds the method-not-allowed handler
// installed by EnableCORS/EnableCORSWithOptions. Preflight OPTIONS
// requests (which chi routes as method-not-allowed, since OPTIONS
// handlers aren't normally registered) are answered with a 204 and the
// methods detected for the requested route. Any other method-not-allowed
// request falls back to the standard 405 + Allow header behavior.
func corsMethodNotAllowedHandler(options CORSOptions) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		var methodsAllowed []methodTyp
		if rctx := RouteContext(r.Context()); rctx != nil {
			methodsAllowed = rctx.methodsAllowed
		}

		if r.Method != http.MethodOptions {
			methodNotAllowedHandler(w, r, methodsAllowed)
			return
		}

		methods := options.AllowMethods
		if names := sortedMethodNames(methodsAllowed); len(names) > 0 {
			methods = names
		}
		w.Header().Set("Access-Control-Allow-Methods", strings.Join(methods, ", "))
		w.WriteHeader(http.StatusNoContent)
	}
}
"}

