// standardMethods lists the methods probed by SetAllowHeader, in the
// stable order they're reported in the Allow header.
var standardMethods = []string{
	http.MethodConnect,
	http.MethodDelete,
	http.MethodGet,
	http.MethodHead,
	http.MethodOptions,
	http.MethodPatch,
	http.MethodPost,
	http.MethodPut,
	http.MethodTrace,
}

// SetAllowHeader adds the Allow header for 405 (method not allowed)
// responses, listing the methods registered for the requested path, per
// RFC 9110 section 15.5.6. It does not inspect the response status code;
// it determines a mismatch itself by checking whether the request's
// method matches the routing tree before calling the next handler.
func SetAllowHeader(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		rctx := chi.RouteContext(r.Context())
		if rctx == nil {
			next.ServeHTTP(w, r)
			return
		}

		routePath := rctx.RoutePath
		if routePath == "" {
			if r.URL.RawPath != "" {
				routePath = r.URL.RawPath
			} else {
				routePath = r.URL.Path
			}
			if routePath == "" {
				routePath = "/"
			}
		}

		if !rctx.Routes.Match(chi.NewRouteContext(), r.Method, routePath) {
			var allowed []string
			for _, method := range standardMethods {
				if rctx.Routes.Match(chi.NewRouteContext(), method, routePath) {
					allowed = append(allowed, method)
				}
			}
			if len(allowed) > 0 {
				w.Header().Set("Allow", strings.Join(allowed, ", "))
			}
		}

		next.ServeHTTP(w, r)
	})
}
"}

